     1→/// Model class representing authentication tokens
     2→class AuthTokens {
     3→  final String accessToken;
     4→  final String idToken;
     5→  final String refreshToken;
     6→  final DateTime expiration;
     7→
     8→  AuthTokens({
     9→    required this.accessToken,
    10→    required this.idToken,
    11→    required this.refreshToken,
    12→    required this.expiration,
    13→  });
    14→
    15→  factory AuthTokens.fromJson(Map<String, dynamic> json) {
    16→    return AuthTokens(
    17→      accessToken: json['access_token'] as String,
    18→      idToken: json['id_token'] as String,
    19→      refreshToken: json['refresh_token'] as String,
    20→      expiration: DateTime.fromMillisecondsSinceEpoch(
    21→        json['expiration'] as int,
    22→      ),
    23→    );
    24→  }
    25→
    26→  Map<String, dynamic> toJson() {
    27→    return {
    28→      'access_token': accessToken,
    29→      'id_token': idToken,
    30→      'refresh_token': refreshToken,
    31→      'expiration': expiration.millisecondsSinceEpoch,
    32→    };
    33→  }
    34→}
