    60→/// Implementation of [AuthLocalDataSource] using [SecurityManager] and SharedPreferences
    61→class AuthLocalDataSourceImpl implements AuthLocalDataSource {
    62→  final SecurityManager _securityManager;
    63→  final SharedPreferences _sharedPreferences;
    64→  static const _userKey = 'user_data';
    65→  static const _authTokenKey = 'auth_token';
    66→  static const _idTokenKey = 'id_token';
    67→  static const _refreshTokenKey = 'refresh_token';
    68→  static const _tokenExpirationKey = 'token_expiration';
    69→
    70→  /// Creates a new [AuthLocalDataSourceImpl] with the given security manager and shared preferences
    71→  AuthLocalDataSourceImpl(this._securityManager, this._sharedPreferences);
    72→
    73→  @override
    74→  Future<void> cacheUser(User user) async {
    75→    if (user is! UserModel) {
    76→      throw ArgumentError('User must be a UserModel instance');
    77→    }
    78→    await _securityManager.write(_userKey, jsonEncode(user.toJson()));
    79→  }
    80→
    81→  @override
    82→  Future<User?> getCachedUser() async {
    83→    final data = await _securityManager.read(_userKey);
    84→    if (data != null) {
    85→      return UserModel.fromJson(jsonDecode(data));
    86→    }
    87→    return null;
    88→  }
    89→
    90→  @override
    91→  Future<void> clearCache() async {
    92→    await _securityManager.deleteAll();
    93→  }
    94→
    95→  @override
    96→  Future<void> saveAuthData(
    97→    String token,
    98→    String refreshToken, {
    99→    DateTime? expiresAt,
   100→    String? idToken,
   101→  }) async {
   102→    await _securityManager.write(_authTokenKey, token);
   103→    await _securityManager.write(_refreshTokenKey, refreshToken);
   104→
   105→    if (idToken != null) {
   106→      await _securityManager.write(_idTokenKey, idToken);
   107→    }
   108→
   109→    if (expiresAt != null) {
   110→      await _securityManager.write(
   111→          _tokenExpirationKey, expiresAt.toIso8601String());
   112→    }
   113→  }
   114→
   115→  @override
   116→  Future<String?> getAuthToken() async {
   117→    return await _securityManager.read(_authTokenKey);
   118→  }
   119→
   120→  @override
   121→  Future<String?> getIdToken() async {
   122→    return await _securityManager.read(_idTokenKey);
   123→  }
   124→
   125→  @override
   126→  Future<String?> getRefreshToken() async {
   127→    return await _securityManager.read(_refreshTokenKey);
   128→  }
   129→
   130→  @override
   131→  Future<bool> isTokenExpired() async {
   132→    final expirationStr = await _securityManager.read(_tokenExpirationKey);
   133→    if (expirationStr == null) return true;
   134→
   135→    final expiration = DateTime.parse(expirationStr);
   136→    return DateTime.now().isAfter(expiration);
   137→  }
   138→
   139→  @override
   140→  Future<DateTime?> getTokenExpiration() async {
   141→    final expiration = await _securityManager.read(_tokenExpirationKey);
   142→    if (expiration == null) return null;
   143→
   144→    return DateTime.parse(expiration);
   145→  }
   146→
   147→  @override
   148→  Future<void> clearAuthData() async {
   149→    await _securityManager.delete(_authTokenKey);
   150→    await _securityManager.delete(_idTokenKey);
   151→    await _securityManager.delete(_refreshTokenKey);
   152→    await _securityManager.delete(_tokenExpirationKey);
   153→  }
   154→
   155→  @override
   156→  Future<bool> hasValidSession() async {
   157→    final token = await getAuthToken();
   158→    if (token == null) return false;
   159→
   160→    final isExpired = await isTokenExpired();
   161→    return !isExpired;
   162→  }
   163→
   164→  @override
   165→  Future<void> cacheAuthToken(String token) async {
   166→    await _securityManager.write(_authTokenKey, token);
   167→  }
   168→
   169→  @override
   170→  Future<void> cacheIdToken(String token) async {
   171→    await _securityManager.write(_idTokenKey, token);
   172→  }
